package com.infy.inventrack.user.service; import com.infy.inventrack.common.constants.InfyInvenTrackConstants; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.common.exception.DuplicateResourceException; import com.infy.inventrack.user.entity.AppUser; import com.infy.inventrack.user.repository.UserRepository; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; @Service public class UserService { private final UserRepository repo; private final PasswordEncoder encoder; public UserService(UserRepository r,PasswordEncoder e){repo=r;encoder=e;} @Transactional public UserResponse registerUser(UserRegistrationRequest r){ if(repo.existsByUserNameIgnoreCase(r.getUserName().trim())) throw new DuplicateResourceException(InfyInvenTrackConstants.DUPLICATE_USERNAME.value()); if(repo.existsByEmailIgnoreCase(r.getEmail().trim())) throw new DuplicateResourceException("Email already exists"); AppUser u=new AppUser(); u.setUserName(r.getUserName().trim()); u.setPassword(encoder.encode(r.getPassword())); u.setEmail(r.getEmail().trim()); u.setRole(r.getRole()); AppUser s=repo.save(u); return new UserResponse(s.getUserId(),s.getUserName(),s.getEmail(),s.getRole()); } }
